import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// Create axios instance
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: { 'Content-Type': 'application/json' },
});

// Add auth token to requests
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Handle auth errors
api.interceptors.response.use(
  (response) => response,
  (error) => {
    console.error('API Error:', error.response?.data || error.message);

    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// Get personalized recommendations for a user
export const getRecommendations = async (limit = 20) => {
  try {
    console.log('🎯 Fetching recommendations...');
    const response = await api.get('/recommendations/for-user', { 
      params: { limit } 
    });

    // Defensive programming - ensure we return an array
    const recommendations = response.data?.recommendations || response.data?.movies || [];

    console.log('✅ Recommendations received:', recommendations.length);
    return {
      recommendations: Array.isArray(recommendations) ? recommendations : [],
      count: recommendations.length
    };
  } catch (error) {
    console.error('❌ Error fetching recommendations:', error);

    // Return empty array as fallback to prevent crashes
    return {
      recommendations: [],
      count: 0,
      error: error.message
    };
  }
};

// Get similar movies to a specific movie
export const getSimilarMovies = async (movieId, limit = 12) => {
  try {
    console.log(`🔍 Fetching similar movies for: ${movieId}`);
    const response = await api.get(`/recommendations/similar/${movieId}`, { 
      params: { limit } 
    });

    // Defensive programming - handle different response structures
    const similarMovies = response.data?.similar_movies || 
                          response.data?.movies || 
                          response.data?.recommendations || 
                          [];

    console.log('✅ Similar movies received:', similarMovies.length);
    return {
      similar_movies: Array.isArray(similarMovies) ? similarMovies : [],
      count: similarMovies.length
    };
  } catch (error) {
    console.error('❌ Error fetching similar movies:', error);

    // Return empty array as fallback
    return {
      similar_movies: [],
      count: 0,
      error: error.message
    };
  }
};

// Get popular movies (fallback when recommendations aren't available)
export const getPopularMovies = async (genre = null, limit = 20) => {
  try {
    console.log('📈 Fetching popular movies...');
    const params = { limit };
    if (genre) params.genre = genre;

    const response = await api.get('/movies/popular', { params });

    const movies = response.data?.movies || [];

    console.log('✅ Popular movies received:', movies.length);
    return {
      movies: Array.isArray(movies) ? movies : [],
      count: movies.length,
      genre
    };
  } catch (error) {
    console.error('❌ Error fetching popular movies:', error);

    return {
      movies: [],
      count: 0,
      error: error.message
    };
  }
};

// Get trending movies
export const getTrendingMovies = async (limit = 12) => {
  try {
    console.log('🔥 Fetching trending movies...');
    const response = await api.get('/recommendations/trending', { 
      params: { limit } 
    });

    const trending = response.data?.movies || response.data?.trending || [];

    return {
      trending: Array.isArray(trending) ? trending : [],
      count: trending.length
    };
  } catch (error) {
    console.error('❌ Error fetching trending movies:', error);

    // Fallback to featured movies
    try {
      const fallbackResponse = await api.get('/movies/featured', { 
        params: { limit } 
      });
      const movies = fallbackResponse.data?.movies || [];

      return {
        trending: Array.isArray(movies) ? movies : [],
        count: movies.length
      };
    } catch (fallbackError) {
      return {
        trending: [],
        count: 0,
        error: error.message
      };
    }
  }
};

// Get recommendations by genre
export const getRecommendationsByGenre = async (genre, limit = 20) => {
  try {
    console.log(`🎭 Fetching ${genre} recommendations...`);
    const response = await api.get('/recommendations/by-genre', { 
      params: { genre, limit } 
    });

    const movies = response.data?.movies || response.data?.recommendations || [];

    return {
      movies: Array.isArray(movies) ? movies : [],
      genre,
      count: movies.length
    };
  } catch (error) {
    console.error('❌ Error fetching genre recommendations:', error);

    // Fallback to regular genre filtering
    try {
      const fallbackResponse = await api.get('/movies/', { 
        params: { genre, limit, sort_by: 'avg_rating' } 
      });
      const movies = fallbackResponse.data?.movies || [];

      return {
        movies: Array.isArray(movies) ? movies : [],
        genre,
        count: movies.length
      };
    } catch (fallbackError) {
      return {
        movies: [],
        genre,
        count: 0,
        error: error.message
      };
    }
  }
};

// Export all functions as default object
export default {
  getRecommendations,
  getSimilarMovies,
  getPopularMovies,
  getTrendingMovies,
  getRecommendationsByGenre
};
